package com.wjx871.population.certificate;import com.wjx871.population.common.ApiResponse;import jakarta.servlet.http.HttpServletRequest;import jakarta.validation.Valid;import java.time.LocalDate;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.format.annotation.DateTimeFormat;import org.springframework.http.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;
@RestController@RequiredArgsConstructor public class CertificateController {private final CertificateService service;
@GetMapping("/api/certificates")@PreAuthorize("hasAuthority('certificate:view')")public ApiResponse<Page<CertificateView>> search(@RequestParam(required=false)Long personId,@RequestParam(required=false)String personName,@RequestParam(required=false)String certificateType,@RequestParam(required=false)String certificateNo,@RequestParam(required=false)String status,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)LocalDate issueDateFrom,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)LocalDate issueDateTo,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)LocalDate expireDateFrom,@RequestParam(required=false)@DateTimeFormat(iso=DateTimeFormat.ISO.DATE)LocalDate expireDateTo,@RequestParam(required=false)Integer expiringWithinDays,Pageable p){return ApiResponse.ok(service.search(personId,personName,certificateType,certificateNo,status,issueDateFrom,issueDateTo,expireDateFrom,expireDateTo,expiringWithinDays,p));}
@GetMapping("/api/certificates/{id}")@PreAuthorize("hasAuthority('certificate:view')")public ApiResponse<CertificateView> get(@PathVariable Long id){return ApiResponse.ok(service.get(id));}
@GetMapping("/api/persons/{id}/certificates")@PreAuthorize("hasAuthority('certificate:view')")public ApiResponse<Page<CertificateView>> person(@PathVariable Long id,Pageable p){return ApiResponse.ok(service.byPerson(id,p));}
@PostMapping("/api/certificates")@ResponseStatus(HttpStatus.CREATED)@PreAuthorize("hasAuthority('certificate:edit')")public ApiResponse<CertificateView> create(@Valid@RequestBody CertificateCreateRequest q,HttpServletRequest h){return ApiResponse.created(service.create(q,h));}
@PutMapping("/api/certificates/{id}")@PreAuthorize("hasAuthority('certificate:edit')")public ApiResponse<CertificateView> update(@PathVariable Long id,@Valid@RequestBody CertificateUpdateRequest q,HttpServletRequest h){return ApiResponse.ok(service.update(id,q,h));}
@PostMapping("/api/certificates/{id}/cancel")@PreAuthorize("hasAuthority('certificate:edit')")public ApiResponse<Void> cancel(@PathVariable Long id,@Valid@RequestBody CertificateCancelRequest q,HttpServletRequest h){service.cancel(id,q,h);return ApiResponse.ok(null);}}
